sql:
SELECT test_runs.test_run_id, test_runs.test_priority
FROM test_runs
WHERE test_runs.test_run_id NOT IN (
    SELECT test_notes.test_run_id
    FROM test_notes
);

SELECT test_setup_id, setup_name
FROM test_setups
WHERE setup_status = 'active';

SELECT test_run_id, test_status, test_priority
FROM test_runs
WHERE test_location = 'Lab B, Site 2';

SELECT test_run_id
FROM test_runs
WHERE test_run_id > 5000;

SELECT note_text, note_priority
FROM test_notes
WHERE created_by = 0;

external_knowledge:
- 'Navigators guiding the data voyages' metaphorically refers to users whose role is 'data analyst';
- 'Coordinates of their latest expeditions' refers to the unique identifiers (`test_run_id`) and version numbers (`version_number`) of the test runs they have created;
- 'Latest expeditions' implies selecting the test runs where the 'data analyst' has been the creator.

Initial sprout: Represents the root test runs with no parent setup (test_setup_id is NULL);
Branches and leafy descendants: Represents child test runs extending from root runs through recursive join;
Whispers of the test's story: Refers to the test notes or observations associated with each test run.

- 'voyages of discovery' metaphorically refers to the test runs;
- 'the insignificance of their quest' is a metaphor for the low priority of the test runs;
- 'vast ocean of testing grounds' represents the various test locations;
- 'names of these minor expeditions' refers to the names of the test types;
- 'harbors' are the locations of the tests;
- 'fates' are the statuses of the tests.

sql:
SELECT test_run_id
FROM test_runs
WHERE test_status = 'completed' AND test_setup_id = 1;

SELECT AVG(seq)
FROM test_data
WHERE test_run_id = 100;

SELECT AVG(data_points) AS average_data_points
FROM (
  SELECT test_run_id, COUNT(*) AS data_points
  FROM test_data
  GROUP BY test_run_id
) AS test_data_counts;

SELECT tr.test_run_id, tt.type_name, tr.test_date, tr.test_location, tr.test_status, tr.test_priority
FROM test_runs tr
INNER JOIN test_types tt ON tr.test_type_id = tt.test_type_id;

SELECT config_name, config_value
FROM test_configurations
WHERE created_by = 1 AND config_value = '50000';

SELECT setup_status
FROM test_setups
WHERE test_setup_id = 1;

SELECT test_run_id, test_date, test_status
FROM test_runs
WHERE created_by = 10;

SELECT software_name 
FROM test_software 
WHERE test_run_id = 1;
